var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……대충 말뜻은 이해했다. 야크샤 부전대장.","JPN":"……だいたい理解した。ヤクシャー副戦隊長。","ENG":"...I see what you're getting at, Yaksha Deputy Commander.","TWN":"……我大概懂你的意思了。夜叉副戰隊長。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"요컨대 이번 작전에 그 신참 녀석을 참관시켜 달라는 뜻이로군.","JPN":"つまり、今回の作戦にその新入りを立ち会わせて欲しいということだな。","ENG":"You want us to bring the rookie along for the next operation to watch.","TWN":"總之，你是想讓新人觀摩這次作戰吧。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇습니다. 펜릴 전대장님.","JPN":"その通りです、フェンリル戦隊長。","ENG":"Yes, Fenrir Commander.","TWN":"是的，芬里爾戰隊長。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"마침, 펜릴 전대가 작전 수행을 위해 이 기지에서 물자를 보급받을 거라고 들었거든요.","JPN":"ちょうどフェンリル戦隊が作戦遂行のために、この基地で物資を補給する予定だと聞きましたので。","ENG":"I heard that the Fenrir Division was coming here for resupplies before the operation.","TWN":"我聽說芬里爾戰隊正好要在這個基地停留，進行物資補給。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아직 외부에 노출되지 않은 작전으로 알고 있는데.","JPN":"まだその作戦については公表されてないはずだが。","ENG":"I was under the impression that this operation was not announced yet.","TWN":"我記得這個作戰並未向外部透露。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"여전히 관리국 소식에는 귀가 밝군.","JPN":"相変わらず管理局の情報に明るいな。","ENG":"I see you're still quick with news around the Administration.","TWN":"你在管理局的消息還是這麼靈通。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하하, 작은 전대 나름의 생존전략이라고 해야할까요?","JPN":"あはは、小規模戦隊なりの生存戦略といったところでしょうか。","ENG":"Haha, let's say it's a survival tactic for small divisions like us.","TWN":"呵呵，這算是小戰隊自己的生存策略吧？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"펜릴 전대의 전대장이라고?","JPN":"フェンリル戦隊の戦隊長か？","ENG":"Is she the Commander of the Fenir Division?","TWN":"她是芬里爾戰隊的戰隊長？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"전대장이라는 게 이런 꼬맹이도…… ","JPN":"戦隊長って、こんなガキにも…… ","ENG":"So even a little kid like her can be a command–","TWN":"這種小鬼也能當戰隊長……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"커헉!?","JPN":"カハッ！？","ENG":"Kuh?!","TWN":"咳？！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자자, 앨리스? 인사부터 해야지~?","JPN":"ささ、アリス？　挨拶がまだでしょ～?","ENG":"Now, now, Alice. Let's introduce you first.","TWN":"好了，艾莉絲？先打個招呼吧～？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"펜릴 전대장님, 이쪽이 야크샤의 견습 대원 앨리스 브레이드우드라고 합니다.","JPN":"フェンリル戦隊長、こちらがヤクシャーの見習い隊員、アリス・ブレイドウッドです。","ENG":"Fenrir Commander, this is Alice Braidwood, Yaksha's trainee.","TWN":"芬里爾戰隊長，這位是艾莉絲·布雷德伍德，夜叉的實習隊員。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 작전에 참관을 부탁드릴 신참이에요.","JPN":"今回の作戦に立ち会わせていただく新入りです。","ENG":"Also the rookie that I wanted you to take with you on your operation.","TWN":"想要觀摩這次作戰的新人。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장! 너……! 이게 무슨 짓이야……!?","JPN":"くっそ！　おまえ……！　なんの真似だ………！？","ENG":"Gah! Hey...! What was that for...?!","TWN":"可惡！你……！你搞什麼……！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"방금은 내가 살려준 거야. 나중에 고마워하게 될 걸?","JPN":"今のは私が助けてあげたんだからね。後で絶対、感謝することになるよ。","ENG":"I just saved you. You'll thank me later.","TWN":"我剛剛救了你一命。以後你會感謝我的。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"알고 있겠지, 야크샤 부전대장?","JPN":"ヤクシャー副戦隊長、わかっていると思うが……","ENG":"I don’t need to elaborate, do I, Yaksha Deputy Commander?","TWN":"夜叉副戰隊長，你知道的吧？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"우리 전대의 작전 사항은 관리국 내에서도 기밀이라 외부에 노출되면 안 돼.","JPN":"うちの戦隊の作戦事項は、管理局内でも機密扱いとなっている。","ENG":"My division's operations are kept confidential even within the Administration.","TWN":"我們戰隊的作戰細節即使在管理局內部也是保密的，絕對不能向外界透露。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"하지만 야크샤와 라이오넬에게는 신세를 진 적이 있지.","JPN":"だが、ヤクシャーとライオネルには世話になったことがあるからな。","ENG":"But I do owe Lionel and Yaksha a favor.","TWN":"但我曾經欠過夜叉和萊諾的人情。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그러니 작전 사항을 외부에 노출하지 않는 조건이라면, 신참의 작전 참관을 허락하겠다.","JPN":"作戦事項を外部に漏らさないと約束してくれるなら、新入りの立ち会いを許可する。","ENG":"So, I will allow her to come along, provided she does not disclose the details of our operation.","TWN":"所以，在作戰細節不對外透露的情況下，我會允許新兵觀摩作戰。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"감사합니다. 펜릴 전대장님.","JPN":"ありがとうございます、フェンリル戦隊長。","ENG":"Thank you, Fenrir Commander.","TWN":"謝謝你，芬里爾戰隊長。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 그럼 이번에는 소방관 아줌마랑 같이 싸우는 거야?","JPN":"え？　じゃあ今回は消防士おばさんと一緒に戦うの？","ENG":"Huh? Am I fighting alongside the firefighter lady?","TWN":"呃？那麼，這次要和消防員阿姨一起戰鬥嗎？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"재밌겠다! 잘 해보자고, 아줌마!","JPN":"楽しそう！　がんばろうね、おばさん！","ENG":"That sounds like fun! Let's do this!","TWN":"很有趣欸！一起好好表現吧，阿姨！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아, 다른 전대 분께 그게 무슨 말버릇이야.","JPN":"キズナ、他所の戦隊の方にそんな言い方はだめだろう。","ENG":"Sooyeon, where are your manners?","TWN":"秀妍，你怎麼和其他戰隊成員說話呢？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"원래 수연이가 사람 보는 눈이 없어서요.","JPN":"キズナは人を見る目がないんです。","ENG":"I'm sorry. She has bad people skills.","TWN":"秀妍這個人說話本來就很直接。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};